using TranSmart.Core.Result;
using TranSmart.Data;
using TranSmart.Data.Paging;
using TranSmart.Domain.Entities.Organization;
using TranSmart.Domain.Models;
using Microsoft.EntityFrameworkCore;
using System.Collections.Generic;
using System;
using System.Linq;
using System.Threading.Tasks;

namespace TranSmart.Service.Organization
{
    public partial interface ITeamService : IBaseService<Team>
    {

    }

    public partial class TeamService : BaseService<Team>, ITeamService
    {
        public TeamService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(Team item, Result<Team> executionResult)
        {
            if (await UOW.GetRepositoryAsync<Team>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(Team.Name), "Name already exists"));
            }
        }
        public override async Task<Team> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<Team>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.Shift).Include(x => x.WeekOffSetup).Include(x => x.WorkHoursSetting),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<Team>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<Team>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<Team>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<Team>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)
                     || x.Description.Contains(search.Name)
                     || x.Shift.Name.Contains(search.Name)),
                include: i => i.Include(x => x.Shift).Include(x => x.WeekOffSetup).Include(x => x.WorkHoursSetting),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Name", ascending: !search.IsDescend);
        }
    }
